      { name: "Tacodeli", price: 10, rating: 4.8, cuisine: "Austin Tacos", tip: "Best breakfast tacos in Austin. The Jess Special (potato, egg, cheese) is the iconic order. Multiple locations." , desc: "Austin's beloved breakfast taco mini-chain — the Jess Special with potato, egg, and cheese is iconic.", photo: "https://upload.wikimedia.org/wikipedia/commons/thumb/9/9e/Carnitas.jpg/800px-Carnitas.jpg"},
      { name: "Veracruz All Natural", price: 10, rating: 4.9, cuisine: "Mexican Tacos", tip: "Austin's most beloved taco truck. The Migas taco and Fresh Fruit agua frescas are a perfect combo." , desc: "Food trailer turned institution serving the city's best migas taco and fresh agua fresca.", photo: "https://upload.wikimedia.org/wikipedia/commons/thumb/6/69/Motherhood_and_apple_pie.jpg/800px-Motherhood_and_apple_pie.jpg"},
      { name: "Uchi", price: 75, rating: 4.9, cuisine: "Japanese Fusion", tip: "Tyson Cole's flagship. Best restaurant in Austin. Omakase at the sushi bar is the move." , desc: "Chef Tyson Cole's Japanese farmhouse-inspired restaurant, Austin's finest omakase experience.", photo: "https://images.unsplash.com/photo-uVOlW570gGw?w=800&auto=format&fit=crop&q=80"},
      { name: "Odd Duck", price: 45, rating: 4.8, cuisine: "Farm-to-Table Texas", tip: "The most creative cooking in Austin. Small plates from local farms. Sunday brunch is special." , desc: "Farm-to-table small plates restaurant with creative seasonal dishes sourced from local Texas farms.", photo: "https://images.unsplash.com/photo-64gSFH63TIY?w=800&auto=format&fit=crop&q=80"},
      { name: "Juan in a Million", price: 10, rating: 4.8, cuisine: "Tex-Mex Breakfast", tip: "East Austin institution. Don Juan taco (huge!) at $5 each. Cash only. Opens 7am." , desc: "East Austin Tex-Mex institution serving the massive Don Juan breakfast taco since 1980.", photo: "https://upload.wikimedia.org/wikipedia/commons/thumb/4/40/Foodiesfeed.com_pouring-honey-on-pancakes-with-walnuts.jpg/800px-Foodiesfeed.com_pouring-honey-on-pancakes-with-walnuts.jpg"},
      { name: "Amy's Ice Creams", price: 5, rating: 4.7, cuisine: "Ice Cream", tip: "Austin's original since 1984. Mexican Vanilla with crushed Oreos is the classic order." , desc: "Austin's original ice cream chain since 1984 with Mexican Vanilla and mix-in performances.", photo: "https://upload.wikimedia.org/wikipedia/commons/thumb/f/f9/An_Ice-cream%2C_Dec_2010.JPG/960px-An_Ice-cream%2C_Dec_2010.JPG"},
      { name: "Valentina's Tex Mex BBQ", price: 16, rating: 4.9, cuisine: "BBQ + Tex-Mex", tip: "South Austin trailer. Brisket breakfast tacos and smoked beef rib. Where BBQ meets Tex-Mex perfection.", localGem: true , desc: "South Austin trailer where smoked brisket meets breakfast tacos — the best of both Texas traditions.", photo: "https://upload.wikimedia.org/wikipedia/commons/thumb/8/87/Nachos-cheese.jpg/800px-Nachos-cheese.jpg"},
      { name: "Asia Cafe", price: 10, rating: 4.7, cuisine: "Sichuan Chinese", tip: "Chinatown Center strip mall. Authentic Sichuan — mapo tofu and dry-fried green beans. $8 lunch specials.", localGem: true , desc: "Chinatown Center strip-mall gem serving authentic Sichuan dishes with real heat and numbing spice.", photo: "https://upload.wikimedia.org/wikipedia/commons/thumb/9/91/Hot_Pot.jpg/800px-Hot_Pot.jpg"},
      { name: "Cisco's Restaurant Bakery", price: 10, rating: 4.8, cuisine: "Tex-Mex Breakfast", tip: "East Austin since 1950. Migas and huevos rancheros. LBJ used to eat here. Old Austin at its best.", localGem: true , desc: "East Austin Tex-Mex breakfast institution since 1950 — LBJ and Willie Nelson were regulars.", photo: "https://upload.wikimedia.org/wikipedia/commons/thumb/d/d2/Full_English_breakfast_%28cropped%29.jpg/800px-Full_English_breakfast_%28cropped%29.jpg"},
      { name: "Lenoir (South Congress)", price: 48, rating: 4.8, cuisine: "Hill Country Tasting Menu", tip: "Pay-what-you-can Tuesday nights at the bar. Chef Jesse Griffiths forages and hunts most of his ingredients." , desc: "South Austin Hill Country tasting menu where the chef forages and hunts many of the ingredients himself.", photo: "https://images.unsplash.com/photo-1555396273-367ea4eb4db5?w=800&q=85"},
      { name: "Micklethwait Craft Meats (East Austin)", price: 18, rating: 4.9, cuisine: "Texas BBQ", tip: "East 5th and Rosewood. Lines shorter than Franklin. The beef rib and the snap of the jalapeño sausage are outstanding.", localGem: true , desc: "Beloved East Austin BBQ trailer with shorter lines than Franklin and equally outstanding beef ribs.", photo: "https://upload.wikimedia.org/wikipedia/commons/thumb/0/08/Brisketphoto.jpg/800px-Brisketphoto.jpg"},
      { name: "Emmer & Rye (Rainey Street)", price: 55, rating: 4.8, cuisine: "Grain-Forward American", tip: "Kevin Fink's grain-focused restaurant. The miso with butter noodles and the duck egg dish are revelatory." , desc: "Rainey Street restaurant where Kevin Fink mills his own ancient grains and forages Texas ingredients.", photo: "https://upload.wikimedia.org/wikipedia/commons/thumb/b/b1/Hot_dog_with_mustard.png/800px-Hot_dog_with_mustard.png"},
      { name: "Fonda San Miguel (North Austin)", price: 45, rating: 4.8, cuisine: "Interior Mexican", tip: "Best Mexican restaurant in Austin — hacienda setting with live mariachi on Sunday. The mole negro is definitive.", localGem: true , desc: "Hacienda-style interior Mexican restaurant with Sunday mariachi and one of Austin's finest mole negro.", photo: "https://upload.wikimedia.org/wikipedia/commons/thumb/a/a5/Tamale_Oaxaque%C3%B1o.jpg/800px-Tamale_Oaxaque%C3%B1o.jpg"},
      { name: "June's All Day (South Lamar)", price: 20, rating: 4.7, cuisine: "California-Inspired All-Day", tip: "South Lamar café. Best avocado toast in Austin and great natural wine list. Open 8am-10pm daily." , desc: "South Lamar all-day café with California-inspired breakfast, lunch, and dinner and excellent natural wines.", photo: "https://images.unsplash.com/photo-1490645935967-10de6ba17061?w=800&q=85"},
        {"name":"Franklin Barbecue","price":25,"rating":4.9,"cuisine":"Texas BBQ","tip":"Arrive by 7 AM to secure a spot in line before the gates open at 11.","desc":"Legendary Central Texas pit-smoked brisket that draws devoted pilgrims from across the country.","photo":"https://images.unsplash.com/photo-DgR5s1xhqA0?w=800&auto=format&fit=crop&q=80"},
        {"name":"La Barbecue","price":22,"rating":4.7,"cuisine":"Texas BBQ","tip":"The beef ribs sell out fast, so go on a weekday for the best shot at snagging one.","desc":"A beloved East Austin trailer-turned-brick-and-mortar known for buttery beef ribs and killer sausage.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/2/20/Balinese_Roasted_Pork_Ribs_-_Iga_Babi_Panggang_Bali.JPG/800px-Balinese_Roasted_Pork_Ribs_-_Iga_Babi_Panggang_Bali.JPG"},
        {"name":"Micklethwait Craft Meats","price":20,"rating":4.7,"cuisine":"Texas BBQ","tip":"Don't skip the scratch-made sides — the jalapeño cheese grits are a hidden highlight.","desc":"Craft-focused trailer smokehouse serving meticulously sourced meats alongside inventive Southern sides.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/0/08/Brisketphoto.jpg/800px-Brisketphoto.jpg"},
        {"name":"Terry Black's Barbecue","price":21,"rating":4.8,"cuisine":"Texas BBQ","tip":"The cafeteria-style line moves fast, making it one of the most efficient BBQ spots in the city.","desc":"A descendant of the storied Black family BBQ dynasty, serving smoky Central Texas classics in a spacious hall.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/2/20/Balinese_Roasted_Pork_Ribs_-_Iga_Babi_Panggang_Bali.JPG/800px-Balinese_Roasted_Pork_Ribs_-_Iga_Babi_Panggang_Bali.JPG"},
        {"name":"Stiles Switch BBQ & Brew","price":19,"rating":4.6,"cuisine":"Texas BBQ","tip":"Pair your plate with one of their rotating local craft beers for the full Texas experience.","desc":"A no-frills North Loop institution that balances old-school smoke craft with a laid-back neighborhood vibe.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/7/72/O_Piornedo%2C_Don%C3%ADs%2C_Cervantes_10.jpg/800px-O_Piornedo%2C_Don%C3%ADs%2C_Cervantes_10.jpg"},
        {"name":"Valentina's Tex-Mex BBQ","price":18,"rating":4.8,"cuisine":"Texas BBQ","tip":"Order the Real Deal Holyfield breakfast taco — smoked brisket and egg wrapped in a fresh tortilla.","desc":"A trailblazing trailer fusing Central Texas smoke traditions with bold Tex-Mex flavors and house tortillas.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/8/87/Nachos-cheese.jpg/800px-Nachos-cheese.jpg"},
        {"name":"Loro Asian Smokehouse","price":24,"rating":4.6,"cuisine":"Texas BBQ","tip":"The smoked brisket fried rice is the must-order dish that bridges both culinary worlds beautifully.","desc":"Aaron Franklin's collaboration with chef Tyson Cole blends Texas smoke with vibrant Asian flavors.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/e/e2/Chicken_fajita_platter%2C_Lone_Star_Texas_Grill%2C_Windsor%2C_Ontario%2C_2025-06-14_03.jpg/800px-Chicken_fajita_platter%2C_Lone_Star_Texas_Grill%2C_Windsor%2C_Ontario%2C_2025-06-14_03.jpg"},
        {"name":"Interstellar BBQ","price":20,"rating":4.7,"cuisine":"Texas BBQ","tip":"Hit up the North Austin location on a Tuesday to avoid weekend crowds while still getting fresh cuts.","desc":"Award-winning suburban smokehouse proving that world-class Texas BBQ lives well beyond the city core.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/2/20/Balinese_Roasted_Pork_Ribs_-_Iga_Babi_Panggang_Bali.JPG/800px-Balinese_Roasted_Pork_Ribs_-_Iga_Babi_Panggang_Bali.JPG"},
        {"name":"LeRoy and Lewis Barbecue","price":22,"rating":4.7,"cuisine":"Texas BBQ","tip":"Check their Instagram the night before — they announce next-day specials like smoked lamb neck or wagyu.","desc":"A forward-thinking trailer smokehouse reinventing BBQ with heritage proteins and unexpected global influences.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/6/69/Motherhood_and_apple_pie.jpg/800px-Motherhood_and_apple_pie.jpg"},
        {"name":"Tacodeli","price":11,"rating":4.7,"cuisine":"Austin Tacos","tip":"The Otto taco — chorizo, potato, and queso — is the quintessential Austin breakfast taco order.","desc":"An Austin institution crafting morning and lunch tacos with local ingredients and house-made Doña Sauce.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/9/9e/Carnitas.jpg/800px-Carnitas.jpg"},
        {"name":"Veracruz All Natural","price":10,"rating":4.8,"cuisine":"Austin Tacos","tip":"The migas taco with house salsa verde is widely considered one of the best breakfast tacos in the city.","desc":"A beloved local taco trailer serving fresh, made-to-order breakfast and lunch tacos with Veracruz flair.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/6/69/Motherhood_and_apple_pie.jpg/800px-Motherhood_and_apple_pie.jpg"},
        {"name":"Juan in a Million","price":12,"rating":4.6,"cuisine":"Austin Tacos","tip":"Get the Don Juan taco — a massive egg, potato, bacon, and cheese classic that fuels an entire day.","desc":"An East Austin landmark famous for enormous breakfast tacos and an always-warm family atmosphere.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/4/40/Foodiesfeed.com_pouring-honey-on-pancakes-with-walnuts.jpg/800px-Foodiesfeed.com_pouring-honey-on-pancakes-with-walnuts.jpg"},
        {"name":"Taco Flats","price":13,"rating":4.5,"cuisine":"Austin Tacos","tip":"Order the nopal (cactus) taco for an authentically Texan ingredient you won't find on every menu.","desc":"A bright, modern taqueria celebrating traditional Mexican fillings with Austin's characteristic creative spin.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/9/9e/Carnitas.jpg/800px-Carnitas.jpg"},
        {"name":"Torchy's Tacos","price":14,"rating":4.5,"cuisine":"Austin Tacos","tip":"Ask for the secret menu Brush Fire taco — jerk chicken with mango habanero sauce and fresh toppings.","desc":"The homegrown Austin chain that launched a taco empire on the back of boldly flavored, playfully named creations.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/9/9e/Carnitas.jpg/800px-Carnitas.jpg"},
        {"name":"Paprika ATX","price":13,"rating":4.6,"cuisine":"Austin Tacos","tip":"The green chorizo taco is a must — herbaceous and bright, it upends every expectation about chorizo.","desc":"A chef-driven taco concept showcasing global spice influences and unexpected ingredient pairings in every bite.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/9/9e/Carnitas.jpg/800px-Carnitas.jpg"},
        {"name":"Pueblo Viejo","price":11,"rating":4.5,"cuisine":"Austin Tacos","tip":"This East Side cash-only spot rewards early birds with fresh tortillas straight off the comal.","desc":"A no-frills neighborhood taqueria keeping Austin's taco roots honest with handmade tortillas and generous fillings.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/b/b2/Barbacoa_%28en_Hidalgo%29.JPG/800px-Barbacoa_%28en_Hidalgo%29.JPG"},
        {"name":"Mi Madre's Restaurant","price":12,"rating":4.6,"cuisine":"Austin Tacos","tip":"The barbacoa on weekends only is slow-cooked overnight and sells out well before noon — plan accordingly.","desc":"A beloved East Austin mainstay that has served faithful weekend barbacoa and breakfast tacos for decades.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/4/48/Vendedora_de_bu%C3%B1uelos.jpg/800px-Vendedora_de_bu%C3%B1uelos.jpg"},
        {"name":"Joe's Bakery & Coffee Shop","price":10,"rating":4.5,"cuisine":"Austin Tacos","tip":"Pair your taco with a pan dulce from the counter — the combination is a true East Austin morning ritual.","desc":"A family-owned East Austin institution dishing out straightforward breakfast tacos since 1962.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/4/4a/Tacos-al-Pastor.jpg/800px-Tacos-al-Pastor.jpg"},
        {"name":"Taqueria Arandas","price":9,"rating":4.4,"cuisine":"Austin Tacos","tip":"The al pastor off the trompo is carved fresh to order — always ask for a sample before committing.","desc":"A straightforward Austin taqueria chain beloved for value-priced street-style tacos made with real trompo al pastor.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/4/4a/Tacos-al-Pastor.jpg/800px-Tacos-al-Pastor.jpg"},
        {"name":"Discada","price":15,"rating":4.6,"cuisine":"Mexican Tacos","tip":"Order the discada — a Northern Mexican mixed-meat cook-up on a plow disc that defines the menu.","desc":"A specialist taqueria bringing the discada tradition of Chihuahua and Coahuila to Central Austin with bold, meaty flavor.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/9/9f/DISCADA.JPG/800px-DISCADA.JPG"},
        {"name":"Cuantos Tacos","price":14,"rating":4.6,"cuisine":"Mexican Tacos","tip":"The birria quesatacos with consommé dipping broth are rich enough to make a full meal out of two.","desc":"A modern taqueria spotlighting regional Mexican taco traditions from Jalisco to the Yucatán.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/e/ec/Enchilada_Rice_Beans.jpg/800px-Enchilada_Rice_Beans.jpg"},
        {"name":"Nixta Taqueria","price":16,"rating":4.8,"cuisine":"Mexican Tacos","tip":"The masa is stone-ground in-house daily — order the tasting flight to appreciate every tortilla variation.","desc":"A James Beard-nominated taqueria championing heirloom corn masa and regionally inspired Mexican taco fillings.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/9/90/Green_pozole%2C_dressed_%2829161841908%29_%28cropped%29.jpg/800px-Green_pozole%2C_dressed_%2829161841908%29_%28cropped%29.jpg"},
        {"name":"La Tunita 512","price":12,"rating":4.5,"cuisine":"Mexican Tacos","tip":"The carne asada taco is the benchmark here — simple, perfectly charred, and topped with two salsas.","desc":"A family-run trailer serving street-faithful Mexican tacos with handmade tortillas and house-charred salsas.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/6/60/Burrito.JPG/800px-Burrito.JPG"},
        {"name":"Taco Rico","price":11,"rating":4.5,"cuisine":"Mexican Tacos","tip":"Cash only and no frills — show up hungry and let the taquero recommend what's freshest that day.","desc":"A no-nonsense street taco stand delivering authentic Mexico City-style tacos with robust house salsas.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/6/60/Burrito.JPG/800px-Burrito.JPG"},
        {"name":"El Pollo Rico","price":13,"rating":4.4,"cuisine":"Mexican Tacos","tip":"The adobo-marinated chicken tacos off the rotisserie are the standout — order double the salsa verde.","desc":"A South Austin mainstay known for fire-roasted pollo tacos and vibrant house-made salsas.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/6/60/Burrito.JPG/800px-Burrito.JPG"},
        {"name":"Tacos El Rancho","price":10,"rating":4.4,"cuisine":"Mexican Tacos","tip":"The lengua (beef tongue) taco is silky and mild — an ideal entry point for adventurous first-timers.","desc":"A beloved Austin taqueria truck slinging regional Mexican classics with house-rendered lard tortillas.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/7/73/001_Tacos_de_carnitas%2C_carne_asada_y_al_pastor.jpg/800px-001_Tacos_de_carnitas%2C_carne_asada_y_al_pastor.jpg"},
        {"name":"Taqueria Chapala","price":10,"rating":4.4,"cuisine":"Mexican Tacos","tip":"The chile relleno taco — battered, fried, and folded in a soft tortilla — is a rare gem worth seeking out.","desc":"A Jalisco-style taqueria tucked into East Austin delivering coastal Mexican preparations at bargain prices.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/6/60/Burrito.JPG/800px-Burrito.JPG"},
        {"name":"Taco Moto","price":12,"rating":4.5,"cuisine":"Mexican Tacos","tip":"The suadero (slow-braised beef brisket) taco is their signature — rich, unctuous, and deeply satisfying.","desc":"A Mexico City-inspired taqueria on wheels known for capital-style suadero and crispy chicharrón tacos.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/6/64/Guacamole_IMGP1271.jpg/800px-Guacamole_IMGP1271.jpg"},
        {"name":"Uchi","price":75,"rating":4.9,"cuisine":"Japanese Fusion","tip":"Book the chef's tasting menu and let the kitchen surprise you — the omakase experience is transformative.","desc":"James Beard Award-winning chef Tyson Cole's flagship restaurant redefining Japanese cuisine through a Texas lens.","photo":"https://images.unsplash.com/photo-uVOlW570gGw?w=800&auto=format&fit=crop&q=80"},
        {"name":"Uchiko","price":65,"rating":4.8,"cuisine":"Japanese Fusion","tip":"The 'time and temperature' dishes — cooked at precise low temps — showcase the kitchen's technical depth.","desc":"Uchi's inventive sibling restaurant exploring Japanese farmhouse tradition through modern fine-dining techniques.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/d/d9/Matcha_Scoop.jpg/800px-Matcha_Scoop.jpg"},
        {"name":"Otoko","price":135,"rating":4.8,"cuisine":"Japanese Fusion","tip":"Reserve months in advance — only 12 seats circle the bar for this intimate omakase experience.","desc":"A hyper-intimate 12-seat omakase bar in South Congress Hotel merging Japanese kaiseki ritual with Texas ingredients.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/9/9a/Dried_soba_noodles_by_FotoosVanRobin.jpg/800px-Dried_soba_noodles_by_FotoosVanRobin.jpg"},
        {"name":"Daruma Ramen","price":22,"rating":4.6,"cuisine":"Japanese Fusion","tip":"The tonkotsu broth is simmered 18 hours — go during off-peak hours to get it at its most focused richness.","desc":"A dedicated ramen-ya bringing authentic Japanese broth traditions to Austin with locally sourced toppings.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/4/43/%E5%B0%8F%E6%96%99%E7%90%86%E3%83%90%E3%83%AB%E3%81%95%E3%81%8F%E3%82%89_%E7%89%B9%E8%A3%BD%E3%81%8A%E3%81%AB%E3%81%8E%E3%82%8A.jpg/800px-%E5%B0%8F%E6%96%99%E7%90%86%E3%83%90%E3%83%AB%E3%81%95%E3%81%8F%E3%82%89_%E7%89%B9%E8%A3%BD%E3%81%8A%E3%81%AB%E3%81%8E%E3%82%8A.jpg"},
        {"name":"Kemuri Tatsu-ya","price":45,"rating":4.7,"cuisine":"Japanese Fusion","tip":"The smoked brisket burnt-end skewer is the dish that defines Austin's most unique culinary crossover.","desc":"An izakaya boldly fusing Texas smoke culture with Japanese yakitori craft in a moody East Side atmosphere.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/4/43/%E5%B0%8F%E6%96%99%E7%90%86%E3%83%90%E3%83%AB%E3%81%95%E3%81%8F%E3%82%89_%E7%89%B9%E8%A3%BD%E3%81%8A%E3%81%AB%E3%81%8E%E3%82%8A.jpg/800px-%E5%B0%8F%E6%96%99%E7%90%86%E3%83%90%E3%83%AB%E3%81%95%E3%81%8F%E3%82%89_%E7%89%B9%E8%A3%BD%E3%81%8A%E3%81%AB%E3%81%8E%E3%82%8A.jpg"},
        {"name":"Ramen Tatsu-ya","price":20,"rating":4.7,"cuisine":"Japanese Fusion","tip":"The Hi-Def (tonkotsu with extra-thick chashu) is the most popular bowl — add a soft-boiled egg.","desc":"The Austin ramen benchmark: rich, meticulously prepared broths served in a high-energy communal setting.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/5/57/Oseti.jpg/800px-Oseti.jpg"},
        {"name":"Musashino Sushi Dokoro","price":55,"rating":4.7,"cuisine":"Japanese Fusion","tip":"Sit at the bar and request omakase — the itamae's daily selections sourced from Japan are extraordinary.","desc":"Austin's most respected traditional sushi restaurant, quietly serving Japanese-import fish to devoted regulars.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/5/57/Oseti.jpg/800px-Oseti.jpg"},
        {"name":"Tomo Japanese Restaurant","price":40,"rating":4.5,"cuisine":"Japanese Fusion","tip":"The chirashi bowl is a sleeper hit — fresh sliced fish over seasoned rice at a fraction of omakase pricing.","desc":"A relaxed West Austin Japanese restaurant balancing classical sushi craft with accessible everyday dining.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/5/57/Oseti.jpg/800px-Oseti.jpg"},
        {"name":"Fukumoto","price":38,"rating":4.5,"cuisine":"Japanese Fusion","tip":"The izakaya small plates are designed for sharing — order broadly and explore the full menu together.","desc":"A neighborhood izakaya in East Austin serving authentic Japanese small plates alongside curated Japanese whisky.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/9/9a/Dried_soba_noodles_by_FotoosVanRobin.jpg/800px-Dried_soba_noodles_by_FotoosVanRobin.jpg"},
        {"name":"Lenoir","price":55,"rating":4.7,"cuisine":"Farm-to-Table Texas","tip":"Request a back patio table — dining under the trees in the garden is a uniquely Austin experience.","desc":"A South Austin pioneer of hyper-local dining, sourcing from named Hill Country farms and changing the menu weekly.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/3/32/Pepperseggplants.jpg/800px-Pepperseggplants.jpg"},
        {"name":"Justine's Brasserie","price":48,"rating":4.6,"cuisine":"Farm-to-Table Texas","tip":"Go late — Justine's doesn't close until 2 AM and the midnight kitchen crowd has an energy all its own.","desc":"A romantic East Austin brasserie blending French culinary spirit with Texas-sourced seasonal ingredients.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/2/20/Marylebone_Farmers_Market_2005.jpg/800px-Marylebone_Farmers_Market_2005.jpg"},
        {"name":"Odd Duck","price":52,"rating":4.7,"cuisine":"Farm-to-Table Texas","tip":"Order five or six small plates between two people — the menu is built for exploration, not single entrées.","desc":"Bryce Gilmore's acclaimed South Lamar restaurant turning Texas-grown ingredients into imaginative shared plates.","photo":"https://images.unsplash.com/photo-64gSFH63TIY?w=800&auto=format&fit=crop&q=80"},
        {"name":"Epicerie","price":42,"rating":4.5,"cuisine":"Farm-to-Table Texas","tip":"The weekend brunch with a Bloody Mary built from house-fermented hot sauce is a neighborhood institution.","desc":"A charming neighborhood café-bistro in Rosedale balancing Texas-sourced produce with classic French bistro cooking.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/2/24/Marketvegetables.jpg/800px-Marketvegetables.jpg"},
        {"name":"Salt & Time Butcher Shop & Salumeria","price":30,"rating":4.6,"cuisine":"Farm-to-Table Texas","tip":"Buy a house-cured charcuterie board for a picnic or stay for the rotating blackboard lunch special.","desc":"A working East Austin salumeria and butcher sourcing whole Texas animals and curing everything in-house.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/2/20/Marylebone_Farmers_Market_2005.jpg/800px-Marylebone_Farmers_Market_2005.jpg"},
        {"name":"Foreign & Domestic","price":50,"rating":4.6,"cuisine":"Farm-to-Table Texas","tip":"The ever-changing pasta dish is a sleeper must-order — fresh and paired with whatever the season offers.","desc":"A North Loop neighborhood restaurant delivering smart, seasonal cooking with both playfulness and precision.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/2/24/Marketvegetables.jpg/800px-Marketvegetables.jpg"},
        {"name":"Emmer & Rye","price":60,"rating":4.7,"cuisine":"Farm-to-Table Texas","tip":"The dim-sum-style roving carts of small plates at dinner are the most fun way to explore the full menu.","desc":"A Rainey Street pioneer serving fermented, milled, and foraged Texas ingredients in a dim, cave-like room.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/0/07/20260112_Pasta_with_meat_%2857869%29.jpg/960px-20260112_Pasta_with_meat_%2857869%29.jpg"},
        {"name":"Jacoby's Restaurant and Mercantile","price":45,"rating":4.5,"cuisine":"Farm-to-Table Texas","tip":"Dine on the sprawling patio overlooking the Colorado River — the setting rivals any in the city.","desc":"A riverside Texas ranch-house restaurant sourcing beef and produce from the Jacoby family's own Hill Country land.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/2/20/Marylebone_Farmers_Market_2005.jpg/800px-Marylebone_Farmers_Market_2005.jpg"},
        {"name":"Barley Swine","price":65,"rating":4.7,"cuisine":"Farm-to-Table Texas","tip":"The tasting menu format is the intended experience — trust the kitchen and pair with their wine selections.","desc":"Bryce Gilmore's intimate North Loop tasting counter showcasing hyper-seasonal Texas ingredients with artisan precision.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/0/0b/RedDot_Burger.jpg/800px-RedDot_Burger.jpg"},
        {"name":"Juan in a Million","price":11,"rating":4.7,"cuisine":"Tex-Mex Breakfast","tip":"Get there before 8 AM on a Sunday to avoid the hour-long wait that forms like clockwork every weekend.","desc":"The East Austin institution that built a legend on the Don Juan breakfast taco and bottomless salsa verde.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/4/40/Foodiesfeed.com_pouring-honey-on-pancakes-with-walnuts.jpg/800px-Foodiesfeed.com_pouring-honey-on-pancakes-with-walnuts.jpg"},
        {"name":"Magnolia Café","price":14,"rating":4.4,"cuisine":"Tex-Mex Breakfast","tip":"Open 24 hours — the 2 AM grill cakes (pancakes) after a night out are a full Austin rite of passage.","desc":"A beloved all-hours Austin diner serving Tex-Mex breakfast staples and grill cakes to night owls since 1979.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/d/d2/Full_English_breakfast_%28cropped%29.jpg/800px-Full_English_breakfast_%28cropped%29.jpg"},
        {"name":"Cisco's Restaurant Bakery & Bar","price":12,"rating":4.5,"cuisine":"Tex-Mex Breakfast","tip":"LBJ was a regular here — order the huevos rancheros and soak up six decades of Austin political history.","desc":"An East Austin breakfast institution open since 1948, famed for migas and the politicians who've filled its booths.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/d/d2/Full_English_breakfast_%28cropped%29.jpg/800px-Full_English_breakfast_%28cropped%29.jpg"},
        {"name":"Polvo's","price":16,"rating":4.5,"cuisine":"Tex-Mex Breakfast","tip":"The weekend brunch enchiladas with tomatillo sauce and two eggs are the standout breakfast plate.","desc":"A South Congress neighborhood staple fusing interior Mexican flavors with Texas-style Tex-Mex brunch comfort.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/4/40/Foodiesfeed.com_pouring-honey-on-pancakes-with-walnuts.jpg/800px-Foodiesfeed.com_pouring-honey-on-pancakes-with-walnuts.jpg"},
        {"name":"Kerbey Lane Café","price":14,"rating":4.4,"cuisine":"Tex-Mex Breakfast","tip":"The queso pancakes — a literal Tex-Mex mashup on a breakfast plate — are worth ordering on a dare.","desc":"A 24-hour Austin original serving Tex-Mex-inflected comfort breakfasts to generations of locals since 1980.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/4/40/Foodiesfeed.com_pouring-honey-on-pancakes-with-walnuts.jpg/800px-Foodiesfeed.com_pouring-honey-on-pancakes-with-walnuts.jpg"},
        {"name":"Las Trancas","price":10,"rating":4.5,"cuisine":"Tex-Mex Breakfast","tip":"This no-menu-item-over-$10 counter shines brightest with huevos con chorizo — simple, honest, filling.","desc":"An unassuming South Austin counter serving traditional Tex-Mex breakfast plates beloved by in-the-know locals.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/d/d2/Full_English_breakfast_%28cropped%29.jpg/800px-Full_English_breakfast_%28cropped%29.jpg"},
        {"name":"El Naranjo","price":18,"rating":4.7,"cuisine":"Tex-Mex Breakfast","tip":"The Sunday brunch chilaquiles in mole negro are among the most complex and rewarding breakfast dishes in Austin.","desc":"Chef Iliana de la Vega's Oaxacan-meets-Texas brunch experience elevating the Tex-Mex morning meal to fine-dining heights.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/6/60/Burrito.JPG/800px-Burrito.JPG"},
        {"name":"Habanero Mexican Cafe","price":11,"rating":4.4,"cuisine":"Tex-Mex Breakfast","tip":"The breakfast burrito stuffed with potato, egg, and refried beans is a giant handheld for under $10.","desc":"A no-frills North Austin neighborhood spot delivering value-driven Tex-Mex breakfast plates all morning long.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/7/75/Breakfast_at_the_Black_Bear_Diner.jpg/800px-Breakfast_at_the_Black_Bear_Diner.jpg"},
        {"name":"Mama's Kitchen","price":13,"rating":4.4,"cuisine":"Tex-Mex Breakfast","tip":"The migas plate here is creamy and generously portioned — a proper Tex-Mex scramble done the old way.","desc":"A homestyle East Austin breakfast spot cooking classic Tex-Mex morning plates with a warm family touch.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/6/69/Motherhood_and_apple_pie.jpg/800px-Motherhood_and_apple_pie.jpg"},
        {"name":"Amy's Ice Creams","price":6,"rating":4.7,"cuisine":"Ice Cream","tip":"Ask the staff to throw in a crush'in mix-in — they'll flip and fold it tableside with dramatic flair.","desc":"Austin's homegrown ice cream institution where tossing and flipping are as much the show as the scoops.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/f/f9/An_Ice-cream%2C_Dec_2010.JPG/960px-An_Ice-cream%2C_Dec_2010.JPG"},
        {"name":"Lick Honest Ice Creams","price":7,"rating":4.7,"cuisine":"Ice Cream","tip":"The goat cheese + thyme flavor sounds odd until you taste it — one of Austin's most debated great scoops.","desc":"A farm-to-cone creamery sourcing Texas dairy and local produce to craft uncommonly creative seasonal flavors.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/6/65/Anton_Faymann_055_Auto_Colour.jpg/960px-Anton_Faymann_055_Auto_Colour.jpg"},
        {"name":"Teo Espresso, Gelato & Bella Cucina","price":7,"rating":4.6,"cuisine":"Ice Cream","tip":"Pair any scoop with an affogato pour — the espresso over cold gelato is a ten-second transformation.","desc":"An Italian-style gelateria in North Loop churning small-batch gelato with imported ingredients and seasonal fruit.","photo":"https://upload.wikimedia.org/wikipedia/commons/e/e1/-Korean_Icecream_-Tasty_-Family_time_-Yummy.jpg"},
        {"name":"Dolce Neve Gelato","price":7,"rating":4.7,"cuisine":"Ice Cream","tip":"The pistachio gelato uses Bronte-origin Sicilian nuts — rich, green, and worth every extra calorie.","desc":"A Neapolitan-trained gelato maker delivering authentic Italian-method gelato on South Congress with impeccable texture.","photo":"https://upload.wikimedia.org/wikipedia/commons/e/e1/-Korean_Icecream_-Tasty_-Family_time_-Yummy.jpg"},
        {"name":"Sno-Beach","price":5,"rating":4.5,"cuisine":"Ice Cream","tip":"Get the cream of coconut condensed milk drizzle on top — it turns shaved ice into a legitimate dessert.","desc":"An Austin summertime staple serving pillowy Hawaiian-style shaved ice with tropical syrups and sweet toppings.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/8/84/A_counter_is_selling_ice_cream.jpg/960px-A_counter_is_selling_ice_cream.jpg"},
        {"name":"Paletas Betty","price":5,"rating":4.6,"cuisine":"Ice Cream","tip":"The mango chamoy paleta — bright, spicy-sweet, and tangy — is the one iconic Austin frozen treat on a stick.","desc":"A South Austin paletería crafting traditional Mexican ice pops with Texas fruit, chili, and tamarind.","photo":"https://upload.wikimedia.org/wikipedia/commons/e/e1/-Korean_Icecream_-Tasty_-Family_time_-Yummy.jpg"},
        {"name":"The Peached Tortilla (Dessert)","price":9,"rating":4.5,"cuisine":"Ice Cream","tip":"The Thai tea soft serve swirled with condensed milk is a Southeast Asian-Texas dessert worth detour.","desc":"An Asian-Southern fusion restaurant whose dessert soft serve program has become a standalone Instagram destination.","photo":"https://upload.wikimedia.org/wikipedia/commons/e/e1/-Korean_Icecream_-Tasty_-Family_time_-Yummy.jpg"},
        {"name":"Manana","price":7,"rating":4.5,"cuisine":"Ice Cream","tip":"The rice horchata soft serve with cinnamon crumble is the dessert that best captures Austin in a cup.","desc":"A Tex-Mex-inspired creamery blending Latin flavors like horchata, cajeta, and tamarind into soft serve and scoops.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/8/84/A_counter_is_selling_ice_cream.jpg/960px-A_counter_is_selling_ice_cream.jpg"},
        {"name":"Cow Tipping Creamery","price":6,"rating":4.6,"cuisine":"Ice Cream","tip":"Choose a base, sauce, and mix-in — the build-your-own soft serve system rewards decisive flavor thinkers.","desc":"An Austin-original soft serve trailer famed for inventive flavor combinations and a customizable sundae bar.","photo":"https://upload.wikimedia.org/wikipedia/commons/e/e1/-Korean_Icecream_-Tasty_-Family_time_-Yummy.jpg"},
        {"name":"Valentina's Tex-Mex BBQ","price":18,"rating":4.8,"cuisine":"BBQ + Tex-Mex","tip":"The smoked brisket taco with avocado salsa verde is Austin's most perfect BBQ-Tex-Mex hybrid bite.","desc":"The trailer that invented Austin's BBQ-Tex-Mex fusion lane, combining pit smoke with fresh handmade tortillas.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/8/87/Nachos-cheese.jpg/800px-Nachos-cheese.jpg"},
        {"name":"Kerlin BBQ","price":19,"rating":4.7,"cuisine":"BBQ + Tex-Mex","tip":"Get the kolache stuffed with smoked brisket — a Czech-Texas mashup that perfectly defines Austin's identity.","desc":"An East Side BBQ trailer pairing Texas pit classics with house-baked Czech kolaches for the ultimate crossover meal.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/6/69/Motherhood_and_apple_pie.jpg/800px-Motherhood_and_apple_pie.jpg"},
        {"name":"Loro Asian Smokehouse","price":24,"rating":4.6,"cuisine":"BBQ + Tex-Mex","tip":"The brisket fried rice is the dish that bridges both kitchens — order it first before anything else.","desc":"The Aaron Franklin and Tyson Cole collab where Texas BBQ collides with Southeast Asian flavor at a lively bar.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/e/e2/Chicken_fajita_platter%2C_Lone_Star_Texas_Grill%2C_Windsor%2C_Ontario%2C_2025-06-14_03.jpg/800px-Chicken_fajita_platter%2C_Lone_Star_Texas_Grill%2C_Windsor%2C_Ontario%2C_2025-06-14_03.jpg"},
        {"name":"JMueller BBQ","price":20,"rating":4.6,"cuisine":"BBQ + Tex-Mex","tip":"The jalapeño cheddar sausage is the side that outshines the mains — order two links minimum.","desc":"A venerable Mueller family lineage BBQ stand blending classic Central Texas smoke craft with Tex-Mex spiced sausages.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/8/87/Nachos-cheese.jpg/800px-Nachos-cheese.jpg"},
        {"name":"Polvos","price":17,"rating":4.5,"cuisine":"BBQ + Tex-Mex","tip":"Order the fajitas with smoked skirt steak — the kitchen chars over wood, giving it real BBQ authenticity.","desc":"A South Congress institution where wood-fired fajitas blur the line between Tex-Mex tradition and Austin BBQ culture.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Chili_con_queso_%28cropped%29.jpg/800px-Chili_con_queso_%28cropped%29.jpg"},
        {"name":"Güero's Taco Bar","price":16,"rating":4.5,"cuisine":"BBQ + Tex-Mex","tip":"Grab an Oak Garden patio table on a Saturday — the live music, smoked meats, and margaritas align perfectly.","desc":"A South Congress landmark fusing BBQ-smoked proteins into a classic Tex-Mex taco and enchilada menu.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/6/69/Motherhood_and_apple_pie.jpg/800px-Motherhood_and_apple_pie.jpg"},
        {"name":"Freedmen's Bar","price":22,"rating":4.6,"cuisine":"BBQ + Tex-Mex","tip":"The smoked queso with brisket drippings is a molten Texas miracle — order it before anything else arrives.","desc":"A West Campus BBQ bar celebrating Central Texas smoke tradition with a craft cocktail program to match.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6e/Chili_con_queso_%28cropped%29.jpg/800px-Chili_con_queso_%28cropped%29.jpg"},
        {"name":"Distant Relatives","price":22,"rating":4.7,"cuisine":"BBQ + Tex-Mex","tip":"The smoked lamb with Tex-Mex spiced sides bridges African-American pit traditions with Texas-Mexican flavors.","desc":"A James Beard-nominated Black pitmaster's restaurant blending African American food heritage with Texas BBQ craft.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/6/69/Motherhood_and_apple_pie.jpg/800px-Motherhood_and_apple_pie.jpg"},
        {"name":"Stiles Switch x Torchy's Collab Pop-up","price":18,"rating":4.5,"cuisine":"BBQ + Tex-Mex","tip":"Follow Stiles Switch on social media for pop-up dates — the smoked brisket Torchy-style taco is limited run.","desc":"An occasional crossover event where Austin's BBQ and taco worlds collide in a smoke-and-tortilla mashup plate.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/8/87/Nachos-cheese.jpg/800px-Nachos-cheese.jpg"},
        {"name":"Wu Chow","price":35,"rating":4.6,"cuisine":"Sichuan Chinese","tip":"The whole Peking duck requires 24-hour advance notice but is the most impressive table dish in Austin's Sichuan scene.","desc":"A modern downtown Chinese restaurant whose Sichuan-forward menu and cocktail program elevate Austin's Chinese dining.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/c/c2/Kung-pao-shanghai.jpg/800px-Kung-pao-shanghai.jpg"},
        {"name":"Chengdu Taste","price":22,"rating":4.7,"cuisine":"Sichuan Chinese","tip":"Order the cumin lamb skewers and mapo tofu together — together they cover the full numbing-spice spectrum.","desc":"An authentic Sichuan restaurant on North Lamar delivering heat and mala (numbing spice) in faithful proportions.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/9/91/Hot_Pot.jpg/800px-Hot_Pot.jpg"},
        {"name":"Sichuan Garden","price":20,"rating":4.5,"cuisine":"Sichuan Chinese","tip":"The dan dan noodles and twice-cooked pork are textbook Sichuan staples done without shortcuts.","desc":"A reliable North Austin Sichuan kitchen serving the core canon of peppercorn-numbing Chengdu classics.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/8/88/Chen_Mapo_Tofu.jpg/800px-Chen_Mapo_Tofu.jpg"},
        {"name":"Jade Garden","price":18,"rating":4.4,"cuisine":"Sichuan Chinese","tip":"The Sichuan cold noodles served at room temperature with chili oil are the ideal summer dish in Texas heat.","desc":"A no-frills Chinese restaurant anchoring Austin's modest Chinatown strip with solid, spice-forward Sichuan cooking.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/c/c2/Kung-pao-shanghai.jpg/800px-Kung-pao-shanghai.jpg"},
        {"name":"618 Chinese Restaurant","price":24,"rating":4.5,"cuisine":"Sichuan Chinese","tip":"The fish-fragrant eggplant — a Sichuan classic with no actual fish — is the sleeper dish on the menu.","desc":"A North Austin Sichuan specialist delivering bold heat and complex layered flavors in a clean dining setting.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/c/c2/Kung-pao-shanghai.jpg/800px-Kung-pao-shanghai.jpg"},
        {"name":"Guo's Sichuan","price":21,"rating":4.5,"cuisine":"Sichuan Chinese","tip":"The beef tendon in chili oil appetizer is a collagen-rich, gelatinous delight that Sichuan veterans crave.","desc":"A family-run Sichuan kitchen focusing on authentic home-style cooking away from the more commercialized chains.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/b/bb/Twice_cooked_pork%2C_Jia_Yan%2C_5_rue_Humblot%2C_Paris_003.jpg/800px-Twice_cooked_pork%2C_Jia_Yan%2C_5_rue_Humblot%2C_Paris_003.jpg"},
        {"name":"Din Tai Fung Austin","price":28,"rating":4.7,"cuisine":"Sichuan Chinese","tip":"Watch the soup dumpling kitchen through the glass window — the precision folding is a performance worth seeing.","desc":"The globally acclaimed Taiwanese dumpling chain with Sichuan-accented specials nestled in the Domain retail district.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/9/91/Hot_Pot.jpg/800px-Hot_Pot.jpg"},
        {"name":"Qi Austin","price":30,"rating":4.5,"cuisine":"Sichuan Chinese","tip":"The fragrant Sichuan hot pot broth with a split spicy-and-clear dual pot is perfect for mixed-spice-tolerance groups.","desc":"A contemporary Sichuan hot pot restaurant bringing tabletop communal cooking with quality broths to downtown Austin.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/8/88/Chen_Mapo_Tofu.jpg/800px-Chen_Mapo_Tofu.jpg"},
        {"name":"Lucky Robot","price":25,"rating":4.4,"cuisine":"Sichuan Chinese","tip":"The Sichuan pepper-forward cocktails were built to echo the menu's mala heat — try one before the food arrives.","desc":"A South Congress Asian fusion bar weaving Sichuan mala flavors into a playful, modern cocktail-and-food menu.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/b/bb/Twice_cooked_pork%2C_Jia_Yan%2C_5_rue_Humblot%2C_Paris_003.jpg/800px-Twice_cooked_pork%2C_Jia_Yan%2C_5_rue_Humblot%2C_Paris_003.jpg"},
        {"name":"Launderette","price":70,"rating":4.7,"cuisine":"Hill Country Tasting Menu","tip":"Book the private chef's table room for a group tasting — the kitchen sends surprise courses not on the menu.","desc":"A critically acclaimed East Austin restaurant inside a converted laundromat delivering ingredient-focused Hill Country cuisine.","photo":"https://images.unsplash.com/photo-1555396273-367ea4eb4db5?w=800&q=85"},
        {"name":"Olamaie","price":80,"rating":4.8,"cuisine":"Hill Country Tasting Menu","tip":"The biscuits served as an amuse-bouche are so legendary they now have their own line at a downtown kiosk.","desc":"A refined Southern restaurant in a converted bungalow celebrating Texas Hill Country heritage through a modern fine-dining lens.","photo":"https://images.unsplash.com/photo-1555396273-367ea4eb4db5?w=800&q=85"},
        {"name":"Dai Due Supper Club","price":75,"rating":4.7,"cuisine":"Hill Country Tasting Menu","tip":"Wednesday's foraged menu changes entirely based on what the team finds in the Hill Country that morning.","desc":"Jesse Griffiths's butcher-and-restaurant celebrating hunted, foraged, and farmed Texas ingredients in a supper club setting.","photo":"https://images.unsplash.com/photo-1555396273-367ea4eb4db5?w=800&q=85"},
        {"name":"Congress Restaurant","price":110,"rating":4.8,"cuisine":"Hill Country Tasting Menu","tip":"The wine pairings curated by the sommelier are essential — each pour is chosen specifically around Texas provenance.","desc":"Austin's most formal fine-dining room serving a nightly tasting menu of Texas products with French technique and restraint.","photo":"https://images.unsplash.com/photo-1555396273-367ea4eb4db5?w=800&q=85"},
        {"name":"Justine's Brasserie","price":55,"rating":4.6,"cuisine":"Hill Country Tasting Menu","tip":"The late-night four-course tasting available after 10 PM offers the best value fine dining window in Austin.","desc":"An East Austin brasserie offering seasonal tasting menu nights that fold Hill Country sourcing into French bistro structure.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/2/20/Marylebone_Farmers_Market_2005.jpg/800px-Marylebone_Farmers_Market_2005.jpg"},
        {"name":"Bullfight","price":65,"rating":4.6,"cuisine":"Hill Country Tasting Menu","tip":"The Sunday wine dinner format — fixed menu, communal tables, one wine pairing — is Austin's best dinner party.","desc":"A Spanish-inflected wine-centric restaurant on South Congress using Hill Country charcuterie and produce as its anchor.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/0/0b/Matador.JPG/800px-Matador.JPG"},
        {"name":"Swift's Attic","price":60,"rating":4.6,"cuisine":"Hill Country Tasting Menu","tip":"The late-night tasting bites at the bar after 10 PM are the city's most underrated fine-dining secret.","desc":"A sixth-floor downtown restaurant serving playfully ambitious small-plate tasting menus inspired by Texas seasonal produce.","photo":"https://images.unsplash.com/photo-1555396273-367ea4eb4db5?w=800&q=85"},
        {"name":"Jeffrey's","price":90,"rating":4.7,"cuisine":"Hill Country Tasting Menu","tip":"The 50-year legacy of this Clarksville institution gives the tasting menu an emotional depth no newcomer can match.","desc":"Austin's oldest fine-dining institution, updated for modern palates while anchoring its identity in Hill Country provenance.","photo":"https://images.unsplash.com/photo-1555396273-367ea4eb4db5?w=800&q=85"},
        {"name":"Arlo Grey","price":75,"rating":4.6,"cuisine":"Hill Country Tasting Menu","tip":"Request a lakeside table — dining above Lady Bird Lake at sunset is one of Austin's most spectacular settings.","desc":"Top Chef winner Kristen Kish's lakeside restaurant pairing seasonal tasting menus with sweeping Lady Bird Lake views.","photo":"https://images.unsplash.com/photo-1555396273-367ea4eb4db5?w=800&q=85"},
        {"name":"Emmer & Rye","price":58,"rating":4.7,"cuisine":"Grain-Forward American","tip":"The milled grain bread service at the start of the meal is edible proof of the kitchen's grain-forward philosophy.","desc":"A Rainey Street restaurant built around an in-house mill, fermenting and milling Texas heritage grains into everything.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/0/07/20260112_Pasta_with_meat_%2857869%29.jpg/960px-20260112_Pasta_with_meat_%2857869%29.jpg"},
        {"name":"Easy Tiger Bake Shop","price":14,"rating":4.6,"cuisine":"Grain-Forward American","tip":"The beer garden pretzel baked fresh daily pairs best with one of their house-fermented grain-malt mustards.","desc":"A downtown bake shop and beer garden committed to fermented, long-proofed grain breads alongside craft Texas beers.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/6/69/Motherhood_and_apple_pie.jpg/800px-Motherhood_and_apple_pie.jpg"},
        {"name":"Bouldin Creek Café","price":15,"rating":4.5,"cuisine":"Grain-Forward American","tip":"The whole grain vegan breakfast bowl with local grain grits is a beloved morning ritual for South Austin regulars.","desc":"A vegetarian South Austin café championing whole grains, legumes, and seasonal produce in its all-day menu.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/f/f1/PatsCheesesteak.jpg/800px-PatsCheesesteak.jpg"},
        {"name":"Quack's 43rd Street Bakery","price":10,"rating":4.5,"cuisine":"Grain-Forward American","tip":"The whole wheat cinnamon roll made with stone-ground flour is the best reason to arrive right at opening.","desc":"A Hyde Park neighborhood bakery institution grinding whole grains into pastries, breads, and satisfying café fare.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/4/44/Original_Mac_n_Cheese_.jpg/800px-Original_Mac_n_Cheese_.jpg"},
        {"name":"Épicerie","price":18,"rating":4.5,"cuisine":"Grain-Forward American","tip":"The grain-based salads with Texas farro or wheat berries change seasonally and are always worth ordering.","desc":"A French-influenced Rosedale café weaving heritage grains into both its bakery case and seasonal savory menu.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/f/f1/PatsCheesesteak.jpg/800px-PatsCheesesteak.jpg"},
        {"name":"Odd Duck","price":50,"rating":4.7,"cuisine":"Grain-Forward American","tip":"The grain bowl rotating with whatever Texas heritage grain is in season is always the unsung hero of the menu.","desc":"Bryce Gilmore's South Austin restaurant placing fermented grain dishes and milled grains at the heart of its plates.","photo":"https://images.unsplash.com/photo-64gSFH63TIY?w=800&auto=format&fit=crop&q=80"},
        {"name":"Better Half Coffee & Cocktails","price":16,"rating":4.5,"cuisine":"Grain-Forward American","tip":"The avocado toast on house-milled seeded rye is the grain-forward brunch anchor that keeps regulars coming back.","desc":"A West Austin all-day café pairing house-baked grain breads with specialty coffee and evening grain-spirit cocktails.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/f/f1/PatsCheesesteak.jpg/800px-PatsCheesesteak.jpg"},
        {"name":"Hank's","price":22,"rating":4.6,"cuisine":"Grain-Forward American","tip":"The pancakes here are made with a grain blend that is lighter and nuttier than any standard buttermilk stack.","desc":"An East Austin neighborhood restaurant rooting its American diner menu in high-quality grain sourcing and fermentation.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/e/e1/Lattice_apple_pie.png/800px-Lattice_apple_pie.png"},
        {"name":"Barley Swine","price":65,"rating":4.7,"cuisine":"Grain-Forward American","tip":"Every course incorporates a grain element in some form — the menu is a masterclass in milled ingredient integration.","desc":"Bryce Gilmore's intimate tasting counter building each course around fermented, milled, or slow-cooked American grains.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/0/0b/RedDot_Burger.jpg/800px-RedDot_Burger.jpg"},
        {"name":"El Naranjo","price":38,"rating":4.8,"cuisine":"Interior Mexican","tip":"Chef Iliana de la Vega's Oaxacan mole negro is made from 30+ ingredients and is worth the full entrée price alone.","desc":"A refined interior Mexican restaurant by Oaxacan-born chef Iliana de la Vega bringing mole, tlayudas, and memelas to Austin.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/6/60/Burrito.JPG/800px-Burrito.JPG"},
        {"name":"Fonda San Miguel","price":48,"rating":4.7,"cuisine":"Interior Mexican","tip":"The Sunday brunch buffet is an Austin institution — arrive for opening to taste all the stations at their freshest.","desc":"Austin's most beloved interior Mexican dining room for over 40 years, set inside a Hacienda colonial and lush garden.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/6/64/Guacamole_IMGP1271.jpg/800px-Guacamole_IMGP1271.jpg"},
        {"name":"Comedor","price":55,"rating":4.7,"cuisine":"Interior Mexican","tip":"The masa tasting — several formats of fresh corn dough in one sitting — is the menu's most educational arc.","desc":"A downtown fine-dining Mexican restaurant exploring regional interior cuisine through an ingredient-focused tasting menu.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/2/22/Collage_Mexican_Cuisine_by_User-EME.png/800px-Collage_Mexican_Cuisine_by_User-EME.png"},
        {"name":"La Condesa","price":42,"rating":4.6,"cuisine":"Interior Mexican","tip":"The rooftop bar's mezcal cocktail program was designed to pair with the kitchen's interior Mexican dishes.","desc":"A Mexico City neighborhood-inspired restaurant serving elevated interior Mexican cuisine in a sleek Second Street setting.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/9/90/Green_pozole%2C_dressed_%2829161841908%29_%28cropped%29.jpg/800px-Green_pozole%2C_dressed_%2829161841908%29_%28cropped%29.jpg"},
        {"name":"El Chile Café y Cantina","price":22,"rating":4.5,"cuisine":"Interior Mexican","tip":"The chiles en nogada — pomegranate, walnut cream, and stuffed poblano — are a seasonal September-only treasure.","desc":"An East Austin Mexican café offering regional classics from Puebla, Oaxaca, and Veracruz at accessible prices.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/6/60/Burrito.JPG/800px-Burrito.JPG"},
        {"name":"Takoba","price":20,"rating":4.5,"cuisine":"Interior Mexican","tip":"The mezcal margarita rimmed with worm salt (sal de gusano) is the most regionally authentic cocktail in Austin.","desc":"A vibrant East Austin Mexican restaurant drawing on Oaxacan tradition for its mezcal list and mole-based dishes.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/7/73/001_Tacos_de_carnitas%2C_carne_asada_y_al_pastor.jpg/800px-001_Tacos_de_carnitas%2C_carne_asada_y_al_pastor.jpg"},
        {"name":"Manuel's","price":28,"rating":4.4,"cuisine":"Interior Mexican","tip":"The mole enchiladas have been on the menu since 1984 and remain among the most consistent dishes in Austin.","desc":"An Austin Downtown stalwart serving interior Mexican cuisine with a refined Congress Avenue bar since the 1980s.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/9/90/Green_pozole%2C_dressed_%2829161841908%29_%28cropped%29.jpg/800px-Green_pozole%2C_dressed_%2829161841908%29_%28cropped%29.jpg"},
        {"name":"Curra's Grill","price":18,"rating":4.4,"cuisine":"Interior Mexican","tip":"The avocado margarita — made with fresh avocado blended into the mix — is a creamy South Austin original.","desc":"A South Austin neighborhood Mexican restaurant known for its avocado margaritas and interior Mexican comfort plates.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/e/ec/Enchilada_Rice_Beans.jpg/800px-Enchilada_Rice_Beans.jpg"},
        {"name":"Habanero Café","price":16,"rating":4.4,"cuisine":"Interior Mexican","tip":"The Yucatecan cochinita pibil with habanero salsa showcases the regional breadth rarely found outside specialty spots.","desc":"A casual interior Mexican café spotlighting underrepresented regional dishes like Yucatecan, Veracruzano, and Guerreran.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/6/64/Guacamole_IMGP1271.jpg/800px-Guacamole_IMGP1271.jpg"},
        {"name":"Picnik Austin","price":18,"rating":4.6,"cuisine":"California-Inspired All-Day","tip":"The butter coffee (grass-fed butter + MCT oil blend) is polarizing but beloved — try it before dismissing the trend.","desc":"Austin's wellness-forward all-day café serving grain-free, California-influenced plates and grass-fed butter drinks.","photo":"https://images.unsplash.com/photo-1490645935967-10de6ba17061?w=800&q=85"},
        {"name":"Café No Sé","price":20,"rating":4.6,"cuisine":"California-Inspired All-Day","tip":"The Baja-influenced fish tacos at brunch channel Ensenada roadside vibes inside a South Congress storefront.","desc":"A California beach-casual all-day eatery on South Congress where fresh produce, avocado, and sunshine guide every plate.","photo":"https://images.unsplash.com/photo-1490645935967-10de6ba17061?w=800&q=85"},
        {"name":"Tearista","price":15,"rating":4.5,"cuisine":"California-Inspired All-Day","tip":"The matcha latte paired with a California-style avocado grain bowl is the cleanest all-day lunch in East Austin.","desc":"A Japanese-California hybrid café blending ceremonial matcha culture with bright, vegetable-forward West Coast bowls.","photo":"https://images.unsplash.com/photo-1490645935967-10de6ba17061?w=800&q=85"},
        {"name":"Jo's Coffee","price":12,"rating":4.6,"cuisine":"California-Inspired All-Day","tip":"The Iced Turbo — cold brew over ice with honey — is the most ordered drink and the one that built the brand.","desc":"An iconic South Congress all-day café anchoring Austin's outdoor culture with California-casual food and great coffee.","photo":"https://images.unsplash.com/photo-1490645935967-10de6ba17061?w=800&q=85"},
        {"name":"Bouldin Creek Café","price":16,"rating":4.5,"cuisine":"California-Inspired All-Day","tip":"The weekend avocado toast with house fermented hot sauce and a local egg is the all-day order for South Austinites.","desc":"A beloved all-day vegetarian café with strong California overtones in its produce-driven, wellness-oriented menu.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/f/f1/PatsCheesesteak.jpg/800px-PatsCheesesteak.jpg"},
        {"name":"Cenote","price":17,"rating":4.5,"cuisine":"California-Inspired All-Day","tip":"Grab a shaded spot in the tree-canopied patio — it is one of the most beautiful all-day outdoor dining spots in Austin.","desc":"An East Austin all-day café with California sensibilities serving grain bowls, avocado plates, and quality espresso drinks.","photo":"https://images.unsplash.com/photo-1490645935967-10de6ba17061?w=800&q=85"},
        {"name":"Launderette","price":35,"rating":4.7,"cuisine":"California-Inspired All-Day","tip":"The all-day menu means you can order the wood-roasted chicken at 2 PM — a California luxury Austin has embraced.","desc":"A converted East Austin laundromat delivering California-influenced wood-fired cooking across breakfast, lunch, and dinner.","photo":"https://images.unsplash.com/photo-1490645935967-10de6ba17061?w=800&q=85"},
        {"name":"Better Half Coffee & Cocktails","price":15,"rating":4.5,"cuisine":"California-Inspired All-Day","tip":"The daytime-to-evening transition from coffee shop to cocktail bar without leaving your table is an Austin rarity.","desc":"A West Austin all-day café-bar blending California health-food sensibility with a serious evening cocktail program.","photo":"https://upload.wikimedia.org/wikipedia/commons/thumb/f/f1/PatsCheesesteak.jpg/800px-PatsCheesesteak.jpg"},
        {"name":"Henbit","price":22,"rating":4.6,"cuisine":"California-Inspired All-Day","tip":"The rotating seasonal grain bowl changes weekly based on farm deliveries — never the same two visits in a row.","desc":"A California-influenced South Austin all-day restaurant celebrating local farm-box ingredients in a bright, airy space.","photo":"https://images.unsplash.com/photo-1490645935967-10de6ba17061?w=800&q=85"}
